class UnionFind:
    def __init__(self):
        self.parent = {}
        self.rank = {}

    def find(self, x):
        if x not in self.parent:
            self.parent[x] = x
            self.rank[x] = 0
            return x

        if self.parent[x] == x:
            return x

        # Path compression
        self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        root_x = self.find(x)
        root_y = self.find(y)

        if root_x != root_y:
            # Union by rank
            if self.rank[root_x] < self.rank[root_y]:
                self.parent[root_x] = root_y
            elif self.rank[root_y] < self.rank[root_x]:
                self.parent[root_y] = root_x
            else:
                self.parent[root_y] = root_x
                self.rank[root_x] += 1
            return True
        return False

def check_satisfiability(equations):
    uf = UnionFind()

    equality_equations_parsed = []
    inequality_equations_parsed = []

    # Parse equations and separate them into equality and inequality lists
    # Assumes equations are in the format "a==b" or "a!=b" where a and b are single characters.
    for eq_str in equations:
        var1 = eq_str[0]
        op = eq_str[1:3]
        var2 = eq_str[3]

        if op == "==":
            equality_equations_parsed.append((var1, var2))
        else:  # op == "!="
            inequality_equations_parsed.append((var1, var2))

    # First pass: Process all '==' equations to establish equivalences
    for var1, var2 in equality_equations_parsed:
        uf.union(var1, var2)

    # Second pass: Process all '!=' equations and check for contradictions
    for var1, var2 in inequality_equations_parsed:
        # If two variables are found to be equal (i.e., in the same set)
        # but the equation states they are not equal, then it's a contradiction.
        if uf.find(var1) == uf.find(var2):
            return False  # Contradiction found

    return True  # No contradictions found
